#include<bits/stdc++.h>
using namespace std;
int bz[305][305];
int h[1000001][5],boom[305][305];
int dx[5]={1,0,0,-1};
int dy[5]={0,1,-1,0};
int k[50005],xa[5000005],ya[5000005];
int m;
int x,y,t,w,i,flag=0;
void bfs(int m)
{
	t=0;
	w=1;
	bz[0][0]=0;
	h[0][1]=0;
	h[0][2]=0;
	h[0][3]=0;
	do
	{
		for(i=0;i<=3;i++)
		{
		   	x=h[t][1]+dx[i];
		   	y=h[t][2]+dy[i];
		    if(x>=0&&x<=302&&y>=0&&y<=302&&(bz[x][y]==999999||h[t][3]+1<bz[x][y]))
		    {  
		   		h[w][1]=x;
		    	h[w][2]=y;
		   		h[w][3]=h[t][3]+1;
				if(bz[x][y]==999999) 
		   		{
		   			flag=1;
					printf("%d",h[w][3]);
		   			return ;
				}
				bz[x][y]=0;
		   		w++;
			}
	    }
	    t++;
	}while(t<w);
	return ;
} 
int main()
{
	int i,j; 
	scanf("%d",&m);
	for(i=0;i<=303;i++)
	{
		for(j=0;j<=303;j++)
		{
			bz[i][j]=999999;
		}
	}
    for(i=1;i<=m;i++)
	{
		scanf("%d%d%d",&xa[i],&ya[i],&k[i]);
		bz[xa[i]][ya[i]]=min(bz[xa[i]][ya[i]],k[i]);
		for(int j=0;j<=3;j++)
		{
			int nx=xa[i]+dx[j];
			int ny=ya[i]+dy[j];
			if(nx>=0&&ny>=0)
			{
				bz[nx][ny]=min(bz[nx][ny],k[i]);
			}
		}
	}
	if(bz[0][0]==999999)
	{
		printf("0");
		return 0;
	}
	else if(bz[0][0]==0)
	{
		printf("-1");
		return 0;
	}
	bfs(m);
	if(flag==0)
	{
		printf("-1");
	}
	return 0; 
}
